arguments.new_str:
using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        // EF Core 9: Migrate() can no longer be called inside a user-started transaction.
        // Migrations manage their own transactions internally.
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            db.Database.Migrate();
        });
    }
}

